class SecurePluginLoader {
  constructor() {
    this.plugins = [];
    this.pluginCache = new Map();
    this.allowedPluginPaths = new Set();
    this.pluginSignatures = new Map();
  }

  setAllowedPluginPaths(paths) {
    paths.forEach(p => {
      const resolved = path.resolve(p);
      this.allowedPluginPaths.add(resolved);
    });
  }

  validatePluginPath(pluginPath) {
    const resolved = path.resolve(pluginPath);
    const normalized = path.normalize(resolved);
    
    if (normalized.includes('..')) {
      throw new Error('Path traversal detected');
    }

    let isAllowed = false;
    for (const allowedPath of this.allowedPluginPaths) {
      if (normalized.startsWith(allowedPath)) {
        isAllowed = true;
        break;
      }
    }

    if (!isAllowed) {
      throw new Error('Plugin path not in allowed directories');
    }

    return normalized;
  }

  verifyPluginSignature(pluginPath, expectedSignature) {
    if (!expectedSignature) {
      return true;
    }

    const content = fs.readFileSync(pluginPath, 'utf8');
    const hash = crypto.createHash('sha256').update(content).digest('hex');
    
    return hash === expectedSignature;
  }

  loadPluginFromFile(pluginPath, signature = null) {
    try {
      const validatedPath = this.validatePluginPath(pluginPath);
      
      if (!fs.existsSync(validatedPath)) {
        throw new Error('Plugin file does not exist');
      }

      const stats = fs.statSync(validatedPath);
      if (!stats.isFile()) {
        throw new Error('Plugin path must be a file');
      }

      if (signature && !this.verifyPluginSignature(validatedPath, signature)) {
        throw new Error('Plugin signature verification failed');
      }

      if (this.pluginCache.has(validatedPath)) {
        return this.pluginCache.get(validatedPath);
      }

      delete require.cache[require.resolve(validatedPath)];
      const plugin = require(validatedPath);
      
      this.validatePlugin(plugin);
      this.pluginCache.set(validatedPath, plugin);
      
      return plugin;
    } catch (error) {
      throw new Error(`Failed to load plugin from file: ${error.message}`);
    }
  }

  loadPluginFromSandbox(code, pluginName) {
    try {
      const sandbox = {
        console: {
          log: (...args) => console.log(`[Plugin:${pluginName}]`, ...args),
          error: (...args) => console.error(`[Plugin:${pluginName}]`, ...args),
          warn: (...args) => console.warn(`[Plugin:${pluginName}]`, ...args)
        },
        Buffer: Buffer,
        setTimeout: setTimeout,
        clearTimeout: clearTimeout,
        setInterval: setInterval,
        clearInterval: clearInterval,
        module: { exports: {} },
        exports: {}
      };

      sandbox.module.exports = sandbox.exports;

      const script = new vm.Script(code, {
        filename: `plugin-${pluginName}.js`,
        timeout: 5000,
        displayErrors: true
      });

      const context = vm.createContext(sandbox);
      script.runInContext(context, {
        timeout: 5000,
        breakOnSigint: true
      });

      const plugin = sandbox.module.exports.default || sandbox.module.exports;
      this.validatePlugin(plugin);
      
      return plugin;
    } catch (error) {
      throw new Error(`Failed to load plugin from sandbox: ${error.message}`);
    }
  }

  validatePlugin(plugin) {
    if (!plugin || typeof plugin !== 'object') {
      throw new Error('Plugin must export an object');
    }

    if (plugin.name && typeof plugin.name !== 'string') {
      throw new Error('Plugin name must be a string');
    }

    const validHooks = ['onRequest', 'onResponse', 'onError'];
    for (const hook of validHooks) {
      if (plugin[hook] && typeof plugin[hook] !== 'function') {
        throw new Error(`Plugin hook ${hook} must be a function`);
      }
    }

    return true;
  }

  registerPlugin(plugin) {
    this.validatePlugin(plugin);
    this.plugins.push(plugin);
  }

  async executeHook(hookName, context) {
    for (const plugin of this.plugins) {
      if (plugin[hookName]) {
        try {
          const result = await Promise.race([
            plugin[hookName](context),
            new Promise((_, reject) => 
              setTimeout(() => reject(new Error('Plugin timeout')), 10000)
            )
          ]);
          
          if (result === false) {
            return false;
          }
        } catch (error) {
          console.error(`Plugin ${plugin.name || 'unknown'} error in ${hookName}:`, error.message);
          if (plugin.onError) {
            try {
              await plugin.onError(error, context);
            } catch (e) {
              console.error(`Plugin error handler failed:`, e.message);
            }
          }
        }
      }
    }
    return true;
  }
}

class APIGateway {
  constructor(config) {
    this.config = config;
    this.pluginLoader = new SecurePluginLoader();
    this.routes = new Map();
    this.initializePlugins();
  }

  initializePlugins() {
    const pluginConfig = this.config.plugins || {};
    
    if (pluginConfig.allowedPaths) {
      this.pluginLoader.setAllowedPluginPaths(pluginConfig.allowedPaths);
    }

    if (pluginConfig.files && Array.isArray(pluginConfig.files)) {
      pluginConfig.files.forEach(fileConfig => {
        try {
          const plugin = this.pluginLoader.loadPluginFromFile(
            fileConfig.path,
            fileConfig.signature
          );
          this.pluginLoader.registerPlugin(plugin);
          console.log(`Loaded plugin from file: ${fileConfig.path}`);
        } catch (error) {
          console.error(`Failed to load plugin from ${fileConfig.path}:`, error.message);
        }
      });
    }

    if (pluginConfig.sandbox && Array.isArray(pluginConfig.sandbox)) {
      pluginConfig.sandbox.forEach(sandboxConfig => {
        try {
          const plugin = this.pluginLoader.loadPluginFromSandbox(
            sandboxConfig.code,
            sandboxConfig.name
          );
          this.pluginLoader.registerPlugin(plugin);
          console.log(`Loaded sandboxed plugin: ${sandboxConfig.name}`);
        } catch (error) {
          console.error(`Failed to load sandboxed plugin ${sandboxConfig.name}:`, error.message);
        }
      });
    }
  }

  addRoute(method, path, target) {
    const key = `${method}:${path}`;
    this.routes.set(key, target);
  }

  findRoute(method, path) {
    const key = `${method}:${path}`;
    return this.routes.get(key);
  }

  async handleRequest(req, res) {
    const startTime = Date.now();
    let body = '';

    req.on('data', chunk => {
      body += chunk.toString();
      if (body.length > 1e6) {
        req.connection.destroy();
      }
    });

    req.on('end', async () => {
      try {
        const parsedUrl = url.parse(req.url, true);
        
        const context = {
          request: {
            method: req.method,
            url: req.url,
            path: parsedUrl.pathname,
            query: parsedUrl.query,
            headers: { ...req.headers },
            body: body
          },
          response: {
            statusCode: 200,
            headers: {},
            body: null
          },
          metadata: {
            startTime: startTime,
            requestId: crypto.randomUUID()
          }
        };

        const continueRequest = await this.pluginLoader.executeHook('onRequest', context);
        
        if (continueRequest === false) {
          this.sendResponse(res, context.response);
          return;
        }

        const target = this.findRoute(context.request.method, context.request.path);
        
        if (!target) {
          context.response.statusCode = 404;
          context.response.body = JSON.stringify({ error: 'Route not found' });
          this.sendResponse(res, context.response);
          return;
        }

        await this.proxyRequest(context, target);
        
        await this.pluginLoader.executeHook('onResponse', context);
        
        this.sendResponse(res, context.response);
        
      } catch (error) {
        console.error('Request handling error:', error);
        
        const errorContext = {
          error: error,
          request: { method: req.method, url: req.url },
          response: {
            statusCode: 500,
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ error: 'Internal server error' })
          }
        };
        
        await this.pluginLoader.executeHook('onError', errorContext);
        this.sendResponse(res, errorContext.response);
      }
    });
  }

  async proxyRequest(context, target) {
    return new Promise((resolve, reject) => {
      const targetUrl = url.parse(target);
      const isHttps = targetUrl.protocol === 'https:';
      const httpModule = isHttps ? https : http;

      const options = {
        hostname: targetUrl.hostname,
        port: targetUrl.port || (isHttps ? 443 : 80),
        path: targetUrl.path + (context.request.path || ''),
        method: context.request.method,
        headers: context.request.headers,
        timeout: 30000
      };

      const proxyReq = httpModule.request(options, (proxyRes) => {
        let data = '';

        proxyRes.on('data', chunk => {
          data += chunk.toString();
        });

        proxyRes.on('end', () => {
          context.response.statusCode = proxyRes.statusCode;
          context.response.headers = { ...proxyRes.headers };
          context.response.body = data;
          resolve();
        });
      });

      proxyReq.on('error', (error) => {
        context.response.statusCode = 502;
        context.response.body = JSON.stringify({ error: 'Bad Gateway' });
        resolve();
      });

      proxyReq.on('timeout', () => {
        proxyReq.destroy();
        context.response.statusCode = 504;
        context.response.body = JSON.stringify({ error: 'Gateway Timeout' });
        resolve();
      });

      if (context.request.body) {
        proxyReq.write(context.request.body);
      }

      proxyReq.end();
    });
  }

  sendResponse(res, response) {
    res.writeHead(response.statusCode, response.headers);
    res.end(response.body);
  }

  start(port = 3000) {
    const server = http.createServer((req, res) => this.handleRequest(req, res));
    
    server.listen(port, () => {
      console.log(`API Gateway listening on port ${port}`);
    });

    return server;
  }
}

